 52â†’// Compactor provides compaction against an underlying storage
 53â†’// of time series data.
 54â†’type Compactor interface {
 55â†’	// Plan returns a set of directories that can be compacted concurrently.
 56â†’	// The directories can be overlapping.
 57â†’	// Results returned when compactions are in progress are undefined.
 58â†’	Plan(dir string) ([]string, error)
 59â†’
 60â†’	// Write persists one or more Blocks into a directory.
 61â†’	// No Block is written when resulting Block has 0 samples and returns an empty slice.
 62â†’	// Prometheus always return one or no block. The interface allows returning more than one
 63â†’	// block for downstream users to experiment with compactor.
 64â†’	Write(dest string, b BlockReader, mint, maxt int64, base *BlockMeta) ([]ulid.ULID, error)
 65â†’
 66â†’	// Compact runs compaction against the provided directories. Must
 67â†’	// only be called concurrently with results of Plan().
 68â†’	// Can optionally pass a list of already open blocks,
 69â†’	// to avoid having to reopen them.
 70â†’	// Prometheus always return one or no block. The interface allows returning more than one
 71â†’	// block for downstream users to experiment with compactor.
 72â†’	// When one resulting Block has 0 samples
 73â†’	//  * No block is written.
 74â†’	//  * The source dirs are marked Deletable.
 75â†’	//  * Block is not included in the result.
 76â†’	Compact(dest string, dirs []string, open []*Block) ([]ulid.ULID, error)
 77â†’}
