243â†’type dirMeta struct {
244â†’	dir  string
245â†’	meta *BlockMeta
246â†’}
247â†’
248â†’// Plan returns a list of compactable blocks in the provided directory.
249â†’func (c *LeveledCompactor) Plan(dir string) ([]string, error) {
250â†’	dirs, err := blockDirs(dir)
251â†’	if err != nil {
252â†’		return nil, err
253â†’	}
254â†’	if len(dirs) < 1 {
255â†’		return nil, nil
256â†’	}
257â†’
258â†’	var dms []dirMeta
259â†’	for _, dir := range dirs {
260â†’		meta, _, err := readMetaFile(dir)
261â†’		if err != nil {
262â†’			return nil, err
263â†’		}
264â†’		if c.blockExcludeFunc != nil && c.blockExcludeFunc(meta) {
265â†’			// Compactions work from oldest to newest, uploads do the same (usually).
266â†’			// If you continue here you'll skip compactions on this one block, but:
267â†’			// * all further blocks are NOT yet uploaded
268â†’			// * some or all further blocks are uploaded
269â†’			//
270â†’			// If we continue and there are newer blocks to pick from,
271â†’			// then you will compact in a non-continuous way, leaving gaps of individual un-compacted blocks.
272â†’			break
273â†’		}
274â†’		dms = append(dms, dirMeta{dir, meta})
275â†’	}
276â†’	return c.plan(dms)
277â†’}
278â†’
279â†’func (c *LeveledCompactor) plan(dms []dirMeta) ([]string, error) {
280â†’	if len(dms) == 0 {
281â†’		return nil, nil
282â†’	}
283â†’
284â†’	slices.SortFunc(dms, func(a, b dirMeta) int {
285â†’		switch {
286â†’		case a.meta.MinTime < b.meta.MinTime:
287â†’			return -1
288â†’		case a.meta.MinTime > b.meta.MinTime:
289â†’			return 1
290â†’		default:
291â†’			return 0
292â†’		}
293â†’	})
294â†’
295â†’	res := c.selectOverlappingDirs(dms)
296â†’	if len(res) > 0 {
297â†’		return res, nil
298â†’	}
299â†’	// No overlapping blocks, do compaction the usual way.
300â†’	// We do not include a recently created block with max(minTime), so the block which was just created from WAL.
301â†’	// This gives users a window of a full block size to piece-wise backup new data without having to care about data overlap.
302â†’	dms = dms[:len(dms)-1]
303â†’
304â†’	for _, dm := range c.selectDirs(dms) {
305â†’		res = append(res, dm.dir)
306â†’	}
307â†’	if len(res) > 0 {
308â†’		return res, nil
309â†’	}
310â†’
311â†’	// Compact any blocks with big enough time range that have >5% tombstones.
312â†’	for i := len(dms) - 1; i >= 0; i-- {
313â†’		meta := dms[i].meta
314â†’		if meta.MaxTime-meta.MinTime < c.ranges[len(c.ranges)/2] {
315â†’			// If the block is entirely deleted, then we don't care about the block being big enough.
316â†’			// TODO: This is assuming a single tombstone is for a distinct series, which might not be true.
317â†’			if meta.Stats.NumTombstones > 0 && meta.Stats.NumTombstones >= meta.Stats.NumSeries {
318â†’				return []string{dms[i].dir}, nil
319â†’			}
320â†’			break
321â†’		}
322â†’		if float64(meta.Stats.NumTombstones)/float64(meta.Stats.NumSeries+1) > 0.05 {
323â†’			return []string{dms[i].dir}, nil
324â†’		}
325â†’	}
326â†’
327â†’	return nil, nil
328â†’}
329â†’
330â†’// selectDirs returns the dir metas that should be compacted into a single new block.
331â†’// If only a single block range is configured, the result is always nil.
332â†’func (c *LeveledCompactor) selectDirs(ds []dirMeta) []dirMeta {
333â†’	if len(c.ranges) < 2 || len(ds) < 1 {
334â†’		return nil
335â†’	}
336â†’
337â†’	highTime := ds[len(ds)-1].meta.MinTime
338â†’
339â†’	for _, iv := range c.ranges[1:] {
340â†’		parts := splitByRange(ds, iv)
341â†’		if len(parts) == 0 {
342â†’			continue
343â†’		}
344â†’
345â†’	Outer:
346â†’		for _, p := range parts {
347â†’			// Do not select the range if it has a block whose compaction failed.
348â†’			for _, dm := range p {
349â†’				if dm.meta.Compaction.Failed {
350â†’					continue Outer
351â†’				}
352â†’			}
353â†’
354â†’			mint := p[0].meta.MinTime
355â†’			maxt := p[len(p)-1].meta.MaxTime
356â†’			// Pick the range of blocks if it spans the full range (potentially with gaps)
357â†’			// or is before the most recent block.
358â†’			// This ensures we don't compact blocks prematurely when another one of the same
359â†’			// size still fits in the range.
360â†’			if (maxt-mint == iv || maxt <= highTime) && len(p) > 1 {
361â†’				return p
362â†’			}
363â†’		}
364â†’	}
365â†’
366â†’	return nil
367â†’}
368â†’
369â†’// selectOverlappingDirs returns all dirs with overlapping time ranges.
370â†’// It expects sorted input by mint and returns the overlapping dirs in the same order as received.
371â†’func (c *LeveledCompactor) selectOverlappingDirs(ds []dirMeta) []string {
372â†’	if !c.enableOverlappingCompaction {
373â†’		return nil
374â†’	}
375â†’	if len(ds) < 2 {
376â†’		return nil
377â†’	}
378â†’	var overlappingDirs []string
379â†’	globalMaxt := ds[0].meta.MaxTime
380â†’	for i, d := range ds[1:] {
381â†’		if d.meta.MinTime < globalMaxt {
382â†’			if len(overlappingDirs) == 0 { // When it is the first overlap, need to add the last one as well.
383â†’				overlappingDirs = append(overlappingDirs, ds[i].dir)
384â†’			}
385â†’			overlappingDirs = append(overlappingDirs, d.dir)
386â†’		} else if len(overlappingDirs) > 0 {
387â†’			break
388â†’		}
389â†’		if d.meta.MaxTime > globalMaxt {
390â†’			globalMaxt = d.meta.MaxTime
391â†’		}
392â†’	}
393â†’	return overlappingDirs
394â†’}
395â†’
396â†’// splitByRange splits the directories by the time range. The range sequence starts at 0.
397â†’//
398â†’// For example, if we have blocks [0-10, 10-20, 50-60, 90-100] and the split range tr is 30
399â†’// it returns [0-10, 10-20], [50-60], [90-100].
400â†’func splitByRange(ds []dirMeta, tr int64) [][]dirMeta {
401â†’	var splitDirs [][]dirMeta
402â†’
403â†’	for i := 0; i < len(ds); {
404â†’		var (
405â†’			group []dirMeta
406â†’			t0    int64
407â†’			m     = ds[i].meta
408â†’		)
409â†’		// Compute start of aligned time range of size tr closest to the current block's start.
410â†’		if m.MinTime >= 0 {
411â†’			t0 = tr * (m.MinTime / tr)
412â†’		} else {
413â†’			t0 = tr * ((m.MinTime - tr + 1) / tr)
414â†’		}
415â†’		// Skip blocks that don't fall into the range. This can happen via mis-alignment or
416â†’		// by being a multiple of the intended range.
417â†’		if m.MaxTime > t0+tr {
418â†’			i++
419â†’			continue
420â†’		}
421â†’
422â†’		// Add all dirs to the current group that are within [t0, t0+tr].
423â†’		for ; i < len(ds); i++ {
424â†’			// Either the block falls into the next range or doesn't fit at all (checked above).
425â†’			if ds[i].meta.MaxTime > t0+tr {
426â†’				break
427â†’			}
428â†’			group = append(group, ds[i])
429â†’		}
430â†’
431â†’		if len(group) > 0 {
432â†’			splitDirs = append(splitDirs, group)
433â†’		}
434â†’	}
435â†’
436â†’	return splitDirs
437â†’}
