483â†’// Compact creates a new block in the compactor's directory from the blocks in the
484â†’// provided directories.
485â†’func (c *LeveledCompactor) Compact(dest string, dirs []string, open []*Block) ([]ulid.ULID, error) {
486â†’	return c.CompactWithBlockPopulator(dest, dirs, open, DefaultBlockPopulator{})
