489â†’func (c *LeveledCompactor) CompactWithBlockPopulator(dest string, dirs []string, open []*Block, blockPopulator BlockPopulator) ([]ulid.ULID, error) {
490â†’	var (
491â†’		blocks []BlockReader
492â†’		bs     []*Block
493â†’		metas  []*BlockMeta
494â†’		uids   []string
495â†’	)
496â†’	start := time.Now()
497â†’
498â†’	for _, d := range dirs {
499â†’		select {
500â†’		case <-c.ctx.Done():
501â†’			return nil, c.ctx.Err()
502â†’		default:
503â†’		}
504â†’
505â†’		meta, _, err := readMetaFile(d)
506â†’		if err != nil {
507â†’			return nil, err
508â†’		}
509â†’
510â†’		var b *Block
511â†’
512â†’		// Use already open blocks if we can, to avoid
513â†’		// having the index data in memory twice.
514â†’		for _, o := range open {
515â†’			if meta.ULID == o.Meta().ULID {
516â†’				b = o
517â†’				break
518â†’			}
519â†’		}
520â†’
