1273â†’	oooTimeWindow := int64(0)
1274â†’	if conf.StorageConfig.TSDBConfig != nil {
1275â†’		oooTimeWindow = conf.StorageConfig.TSDBConfig.OutOfOrderTimeWindow
1276â†’		db.opts.staleSeriesCompactionThreshold.Store(conf.StorageConfig.TSDBConfig.StaleSeriesCompactionThreshold)
1277â†’		// Update retention configuration if provided.
1278â†’		if conf.StorageConfig.TSDBConfig.Retention != nil {
1279â†’			db.retentionMtx.Lock()
1280â†’			if conf.StorageConfig.TSDBConfig.Retention.Time > 0 {
1281â†’				db.opts.RetentionDuration = int64(conf.StorageConfig.TSDBConfig.Retention.Time)
1282â†’				db.metrics.retentionDuration.Set((time.Duration(db.opts.RetentionDuration) * time.Millisecond).Seconds())
1283â†’			}
1284â†’			if conf.StorageConfig.TSDBConfig.Retention.Size > 0 {
1285â†’				db.opts.MaxBytes = int64(conf.StorageConfig.TSDBConfig.Retention.Size)
1286â†’				db.metrics.maxBytes.Set(float64(db.opts.MaxBytes))
1287â†’			}
1288â†’			if conf.StorageConfig.TSDBConfig.Retention.Percentage > 0 {
1289â†’				db.opts.MaxPercentage = conf.StorageConfig.TSDBConfig.Retention.Percentage
1290â†’				db.metrics.maxPercentage.Set(float64(db.opts.MaxPercentage))
1291â†’			}
1292â†’			db.retentionMtx.Unlock()
1293â†’		}
1294â†’	} else {
1295â†’		db.opts.staleSeriesCompactionThreshold.Store(0)
1296â†’	}
1297â†’	if oooTimeWindow < 0 {
1298â†’		oooTimeWindow = 0
1299â†’	}
1300â†’
1301â†’	// Create WBL if it was not present and if OOO is enabled with WAL enabled.
1302â†’	var wblog *wlog.WL
1303â†’	var err error
1304â†’	switch {
1305â†’	case db.head.wbl != nil:
1306â†’		// The existing WBL from the disk might have been replayed while OOO was disabled.
1307â†’		wblog = db.head.wbl
1308â†’	case !db.oooWasEnabled.Load() && oooTimeWindow > 0 && db.opts.WALSegmentSize >= 0:
1309â†’		segmentSize := wlog.DefaultSegmentSize
1310â†’		// Wal is set to a custom size.
1311â†’		if db.opts.WALSegmentSize > 0 {
1312â†’			segmentSize = db.opts.WALSegmentSize
1313â†’		}
1314â†’		oooWalDir := filepath.Join(db.dir, wlog.WblDirName)
1315â†’		wblog, err = wlog.NewSize(db.logger, db.registerer, oooWalDir, segmentSize, db.opts.WALCompression)
1316â†’		if err != nil {
1317â†’			return err
1318â†’		}
1319â†’	}
1320â†’
1321â†’	db.opts.OutOfOrderTimeWindow = oooTimeWindow
1322â†’	db.head.ApplyConfig(conf, wblog)
1323â†’
1324â†’	if !db.oooWasEnabled.Load() {
1325â†’		db.oooWasEnabled.Store(oooTimeWindow > 0)
1326â†’	}
1327â†’	return nil
1328â†’}
