1410â†’// Compact data if possible. After successful compaction blocks are reloaded
1411â†’// which will also delete the blocks that fall out of the retention window.
1412â†’// Old blocks are only deleted on reloadBlocks based on the new block's parent information.
1413â†’// See DB.reloadBlocks documentation for further information.
1414â†’func (db *DB) Compact(ctx context.Context) (returnErr error) {
1415â†’	db.cmtx.Lock()
1416â†’	defer db.cmtx.Unlock()
1417â†’	defer func() {
1418â†’		if returnErr != nil && !errors.Is(returnErr, context.Canceled) {
1419â†’			// If we got an error because context was canceled then we're most likely
1420â†’			// shutting down TSDB and we don't need to report this on metrics
1421â†’			db.metrics.compactionsFailed.Inc()
1422â†’		}
1423â†’	}()
1424â†’
1425â†’	lastBlockMaxt := int64(math.MinInt64)
1426â†’	defer func() {
1427â†’		if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
1428â†’			returnErr = errors.Join(returnErr, fmt.Errorf("WAL truncation in Compact defer: %w", err))
1429â†’		}
1430â†’	}()
1431â†’
1432â†’	start := time.Now()
1433â†’	// Check whether we have pending head blocks that are ready to be persisted.
1434â†’	// They have the highest priority.
1435â†’	for {
1436â†’		select {
1437â†’		case <-db.stopc:
1438â†’			return nil
1439â†’		default:
1440â†’		}
1441â†’
1442â†’		if !db.head.compactable() {
1443â†’			// Reset the counter once the head compactions are done.
1444â†’			// This would also reset it if a manual compaction was triggered while the auto compaction was in its delay period.
1445â†’			if !db.timeWhenCompactionDelayStarted.IsZero() {
1446â†’				db.timeWhenCompactionDelayStarted = time.Time{}
1447â†’			}
1448â†’			break
1449â†’		}
1450â†’
1451â†’		if db.timeWhenCompactionDelayStarted.IsZero() {
1452â†’			// Start counting for the delay.
1453â†’			db.timeWhenCompactionDelayStarted = time.Now()
1454â†’		}
1455â†’		if db.waitingForCompactionDelay() {
1456â†’			break
1457â†’		}
1458â†’		mint := db.head.MinTime()
1459â†’		maxt := rangeForTimestamp(mint, db.head.chunkRange.Load())
1460â†’
1461â†’		// Wrap head into a range that bounds all reads to it.
1462â†’		// We remove 1 millisecond from maxt because block
1463â†’		// intervals are half-open: [b.MinTime, b.MaxTime). But
1464â†’		// chunk intervals are closed: [c.MinTime, c.MaxTime];
1465â†’		// so in order to make sure that overlaps are evaluated
1466â†’		// consistently, we explicitly remove the last value
1467â†’		// from the block interval here.
1468â†’		rh := NewRangeHeadWithIsolationDisabled(db.head, mint, maxt-1)
1469â†’
1470â†’		// Compaction runs with isolation disabled, because head.compactable()
1471â†’		// ensures that maxt is more than chunkRange/2 back from now, and
1472â†’		// head.appendableMinValidTime() ensures that no new appends can start within the compaction range.
1473â†’		// We do need to wait for any overlapping appenders that started previously to finish.
1474â†’		db.head.WaitForAppendersOverlapping(rh.MaxTime())
1475â†’
1476â†’		if err := db.compactHead(rh); err != nil {
1477â†’			return fmt.Errorf("compact head: %w", err)
1478â†’		}
1479â†’		// Consider only successful compactions for WAL truncation.
1480â†’		lastBlockMaxt = maxt
1481â†’	}
1482â†’
1483â†’	// Clear some disk space before compacting blocks, especially important
1484â†’	// when Head compaction happened over a long time range.
1485â†’	if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
1486â†’		return fmt.Errorf("WAL truncation in Compact: %w", err)
1487â†’	}
1488â†’
1489â†’	compactionDuration := time.Since(start)
1490â†’	if compactionDuration.Milliseconds() > db.head.chunkRange.Load() {
1491â†’		db.logger.Warn(
1492â†’			"Head compaction took longer than the block time range, compactions are falling behind and won't be able to catch up",
1493â†’			"duration", compactionDuration.String(),
1494â†’			"block_range", db.head.chunkRange.Load(),
1495â†’		)
1496â†’	}
1497â†’
1498â†’	if lastBlockMaxt != math.MinInt64 {
1499â†’		// The head was compacted, so we compact OOO head as well.
1500â†’		if err := db.compactOOOHead(ctx); err != nil {
1501â†’			return fmt.Errorf("compact ooo head: %w", err)
1502â†’		}
1503â†’	}
1504â†’
1505â†’	return db.compactBlocks()
1506â†’}
