1587â†’// compactOOO creates a new block per possible block range in the compactor's directory from the OOO Head given.
1588â†’// Each ULID in the result corresponds to a block in a unique time range.
1589â†’// The db.cmtx mutex should be held before calling this method.
1590â†’func (db *DB) compactOOO(dest string, oooHead *OOOCompactionHead) (_ []ulid.ULID, err error) {
1591â†’	db.logger.Info("out-of-order compaction started")
1592â†’	start := time.Now()
1593â†’
1594â†’	blockSize := oooHead.ChunkRange()
1595â†’	oooHeadMint, oooHeadMaxt := oooHead.MinTime(), oooHead.MaxTime()
1596â†’	ulids := make([]ulid.ULID, 0)
1597â†’	defer func() {
1598â†’		if err != nil {
1599â†’			// Best effort removal of created block on any error.
1600â†’			for _, uid := range ulids {
1601â†’				_ = os.RemoveAll(filepath.Join(db.dir, uid.String()))
1602â†’			}
1603â†’		}
1604â†’	}()
1605â†’
1606â†’	meta := &BlockMeta{}
1607â†’	meta.Compaction.SetOutOfOrder()
1608â†’	for t := blockSize * (oooHeadMint / blockSize); t <= oooHeadMaxt; t += blockSize {
1609â†’		mint, maxt := t, t+blockSize
1610â†’		// Block intervals are half-open: [b.MinTime, b.MaxTime). Block intervals are always +1 than the total samples it includes.
1611â†’		uids, err := db.compactor.Write(dest, oooHead.CloneForTimeRange(mint, maxt-1), mint, maxt, meta)
1612â†’		if err != nil {
1613â†’			return nil, err
1614â†’		}
1615â†’		ulids = append(ulids, uids...)
1616â†’	}
1617â†’
1618â†’	if len(ulids) == 0 {
1619â†’		db.logger.Info(
1620â†’			"compact ooo head resulted in no blocks",
1621â†’			"duration", time.Since(start),
1622â†’		)
1623â†’		return nil, nil
1624â†’	}
1625â†’
1626â†’	db.logger.Info(
1627â†’		"out-of-order compaction completed",
1628â†’		"duration", time.Since(start),
1629â†’		"ulids", fmt.Sprintf("%v", ulids),
1630â†’	)
1631â†’	return ulids, nil
1632â†’}
